  {
    name: "has-denied",
    dependencies: { lodash: "^4.17.0", "bad-pkg": "1.0.0" },
    licenses: { lodash: "MIT", "bad-pkg": "GPL-3.0" },
    expected: { total: 2, approved: 1, denied: 1, unknown: 0 },
